//-------------------------------------------------------------------------
// 신규매입승인 등록
//-------------------------------------------------------------------------
scwin.f_NewPurchaseAdmission = async function () {
  // Data 변경 여부 조회
  if (ds_dateEachRailroadFareList.getModifiedIndex().length == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["자료"]);
    return;
  }

  // 매입승인구분(FS262)이 02:승인이 아닌 경우
  var pchsAdmitClsCd = "";
  for (var i = 0; i < ds_dateEachRailroadFareList.getRowCount(); i++) {
    pchsAdmitClsCd = ds_dateEachRailroadFareList.getCellData(i, "pchsAdmitClsCd");
    if (ds_dateEachRailroadFareList.getCellData(i, "chk") == "T") {
      if (pchsAdmitClsCd == "02") {
        $c.win.alert($p, "매입승인구분이 미승인, 보류인 경우만 가능합니다.");
        return;
      }
    }
  }

  // 매입예정일자 체크
  if (!(await $c.gus.cfValidate($p, [ica_pchsIntendDt]))) {
    return;
  }
  if (await $c.win.confirm($p, MSG_CM_CRM_001)) {
    // 저장하시겠습니까?		
    dma_purchaseCerti.set("selpchItemCd", "0134"); // 매출입항목코드(철송임)
    dma_purchaseCerti.set("pchsGoodsPatternCd", "01"); // 매입품목유형코드(CONTAINER단위)

    dma_purchaseCerti.set("pchsDeptCd", ed_pchsDeptCd.getValue());
    dma_purchaseCerti.set("pchsClntNo", ed_pchsClntNo.getValue());
    console.log(dma_purchaseCerti.getJSON());

    /*
    tr_saveDateEachRailroadFareList.KeyValue = "Servlet(I:IN_DS1=dma_purchaseCerti, I:IN_DS2=ds_dateEachRailroadFareList)";
    tr_saveDateEachRailroadFareList.Action = "/ds.fs.adjm.pchscerticoll.RegistRailroadFareNewAdmissionCMD.do";								
    tr_saveDateEachRailroadFareList.Post();				    
    */
    $c.sbm.execute($p, sbm_NewPurchaseAdmission);
  }
};

