//-------------------------------------------------------------------------
scwin.f_PurchaseAdmissionCancel = async function () {
  // Data 변경 여부 조회
  if (ds_dateEachRailroadFareList.getModifiedIndex().length == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["자료"]);
    return;
  }

  // 매입승인구분(FS262)이 02:승인인 경우와 매입확정 이전인 경우
  var pchsAdmitClsCd = "";
  var pchsEvidYn = "";
  for (var i = 0; i < ds_dateEachRailroadFareList.getRowCount(); i++) {
    pchsAdmitClsCd = ds_dateEachRailroadFareList.getCellData(i, "pchsAdmitClsCd");
    pchsEvidYn = ds_dateEachRailroadFareList.getCellData(i, "pchsEvidYn");
    if (ds_dateEachRailroadFareList.getCellData(i, "chk") == "T") {
      if (pchsAdmitClsCd != "02") {
        $c.win.alert($p, "매입승인구분이 승인인 경우만 가능합니다.");
        return;
      }
      if (pchsEvidYn == "Y") {
        $c.win.alert($p, "매입확정 이전인 경우만 가능합니다.");
        return;
      }
    }
  }
  if (await $c.win.confirm($p, MSG_CM_CRM_001)) {
    // 저장하시겠습니까?	
    /*
    tr_saveDateEachRailroadFareList.KeyValue = "Servlet(I:IN_DS1=ds_dateEachRailroadFareList)";
    tr_saveDateEachRailroadFareList.Action = "/ds.fs.adjm.pchscerticoll.RegistRailroadFareAdmissionCancelCMD.do";								
    tr_saveDateEachRailroadFareList.Post();				    
    */
    $c.sbm.execute($p, sbm_PurchaseAdmissionCancel);
  }
};

